rss.channel:
{% if target == "blog" -%}
  {{ site.base_url }}blog/
  Blake Rain's Blog Posts
  Recent blog posts by Blake Rain

{%- elif target == "notes" -%}
  {{ site.base_url }}notes/
  Blake Rain's Notes
  Recent notes by Blake Rain

{%- else -%}
  {{ site.base_url }}
  Blake Rain
  Recent content by Blake Rain

{%- endif %}
en-GB
blake@blakerain.com (Blake Rain)
blake@blakerain.com (Blake Rain)
{{ env.now | datetime(format="rfc2822") }}
{% if target == "blog" -%}
  {% set pages = load_pages("blog") -%}
{%- elif target == "notes" -%}
  {% set pages = load_pages("notes") -%}
{%- else -%}
  {% set pages = load_pages("blog") -%}
  {% set pages = pages | chain(load_pages("notes")) -%}
  {% set pages = pages | chain(load_pages("weeknotes")) -%}
{%- endif %}
{%- set pages = pages | sort(attribute="frontmatter.date") | reverse -%}
{% for page in pages -%}
{% if not page.frontmatter.rss or not page.frontmatter.rss.skip -%}


  {{ page.frontmatter.title | default(page.path) }}
  {{ base_url(path_parent(page.path)) | safe }}/
  {{ page.frontmatter.date | datetime(format="rfc2822") }}
  blake@blakerain.com (Blake Rain)
  {{ base_url(path_parent(page.path)) | safe }}

    TOOD: put the content here
    <hr>
    <p>Thanks for reading this post via RSS! 👋</p>
    <a href="mailto:blake@blakerain.com?subject=Feedback on {{ page.path }}">Reply to this post by email</a>


{%- endif %}
{% endfor %}
